// Прокси: собираем multipart/form-data и шлём в table-merger Python-сервис.
// Использует нативный Node.js fetch (а не helpers.httpRequest/axios, который
// портит multipart). Body ответа читается через stream (надёжнее arrayBuffer
// в Node.js нативном fetch). В json итога — debug-поля для диагностики.

const MERGER_URLS = [
  { url: 'http://host.docker.internal:8082/merge', timeout: 8000   },
  { url: 'http://127.0.0.1:8082/merge',            timeout: 180000 }
];

const input = $input.first();
const binary = input.binary || {};
const binaryKeys = Object.keys(binary);
console.log('[table-merger] входных binary-полей:', binaryKeys.length, binaryKeys);

if (binaryKeys.length === 0) {
  return [{ json: { success: false, error: 'Не загружено ни одного файла.' } }];
}

const boundary = '----WebKitFormBoundary' + Math.random().toString(16).slice(2) + Date.now().toString(16);
const chunks = [];
for (const key of binaryKeys) {
  const meta = binary[key];
  const buf = await this.helpers.getBinaryDataBuffer(0, key);
  const filename = (meta.fileName || (key + '.bin')).replace(/"/g, '');
  const contentType = meta.mimeType || 'application/octet-stream';
  chunks.push(Buffer.from('--' + boundary + '\r\n', 'utf8'));
  chunks.push(Buffer.from('Content-Disposition: form-data; name="files"; filename="' + filename + '"\r\n', 'utf8'));
  chunks.push(Buffer.from('Content-Type: ' + contentType + '\r\n\r\n', 'utf8'));
  chunks.push(buf);
  chunks.push(Buffer.from('\r\n', 'utf8'));
}
chunks.push(Buffer.from('--' + boundary + '--\r\n', 'utf8'));
const body = Buffer.concat(chunks);
console.log('[table-merger] multipart body size:', body.length);

let response = null;
let usedUrl = '';
let lastErrMsg = '';
for (const entry of MERGER_URLS) {
  let timer = null;
  const controller = new AbortController();
  try {
    timer = setTimeout(() => controller.abort(), entry.timeout);
    const r = await fetch(entry.url, {
      method: 'POST',
      headers: { 'Content-Type': 'multipart/form-data; boundary=' + boundary },
      body: body,
      signal: controller.signal
    });
    clearTimeout(timer);
    console.log('[table-merger] fetch', entry.url, 'status:', r.status);
    if (!r.ok) {
      let bodyText = '';
      try { bodyText = await r.text(); } catch (_) {}
      let errMsg = 'HTTP ' + r.status;
      try {
        const parsed = JSON.parse(bodyText);
        if (parsed && parsed.detail) errMsg = parsed.detail;
        else if (bodyText) errMsg = bodyText.slice(0, 500);
      } catch (_) {
        if (bodyText) errMsg = bodyText.slice(0, 500);
      }
      return [{ json: { success: false, error: errMsg } }];
    }
    response = r;
    usedUrl = entry.url;
    break;
  } catch (e) {
    if (timer) clearTimeout(timer);
    lastErrMsg = (e && e.message) ? e.message : String(e);
    console.log('[table-merger] fetch error на', entry.url, ':', lastErrMsg);
    continue;
  }
}

if (!response) {
  return [{ json: { success: false, error: 'table-merger сервис недоступен. Запусти start.bat на хост-машине (порт 8082). Последняя ошибка: ' + lastErrMsg } }];
}

const cd = response.headers.get('content-disposition') || '';
const respContentLength = response.headers.get('content-length') || '';
console.log('[table-merger] response content-length:', respContentLength, '| content-disposition:', cd);

let outFilename = 'merged.bin';
let m = cd.match(/filename\*=UTF-8''([^;]+)/i);
if (m) {
  try { outFilename = decodeURIComponent(m[1]); } catch (_) { outFilename = m[1]; }
} else {
  m = cd.match(/filename="?([^";]+)"?/i);
  if (m) outFilename = m[1];
}
const outMime = response.headers.get('content-type') || 'application/octet-stream';

// Читаем body через ReadableStream — надёжнее чем arrayBuffer() в нативном Node.js fetch.
const parts = [];
const reader = response.body.getReader();
while (true) {
  const { done, value } = await reader.read();
  if (done) break;
  parts.push(Buffer.from(value));
}
const outBuffer = Buffer.concat(parts);
console.log('[table-merger] stream parts:', parts.length, '| outBuffer size:', outBuffer.length);

if (outBuffer.length === 0) {
  return [{ json: { success: false, error: 'Пустой ответ от Python-сервиса (' + usedUrl + '). content-length: ' + respContentLength + ', parts: ' + parts.length + '. Проверь логи start.bat — был ли POST /merge.' } }];
}

const binaryData = await this.helpers.prepareBinaryData(outBuffer, outFilename, outMime);

return [{
  json: {
    success: true,
    filename: outFilename,
    size: outBuffer.length,
    files: binaryKeys.length,
    debug: { usedUrl: usedUrl, respContentLength: respContentLength, streamParts: parts.length }
  },
  binary: { data: binaryData }
}];
